class Solution {
public:
    int minSwapsCouples(vector<int>& row) {
        int n=row.size()/2;
        vector<int> pos(row.size());
        for(int i=0;i<(int)row.size();i++) pos[row[i]]=i;
        auto partner=[&](int x){ return x^1; };
        vector<char> seen(n); int ans=0;
        for(int i=0;i<n;i++){
            if(seen[i]) continue;
            int cur=i, cyc=0;
            while(!seen[cur]){
                seen[cur]=1; cyc++;
                int p=partner(row[2*cur])/2;
                cur=p;
            }
            ans+=cyc-1;
        }
        return ans;
    }
};

